const Q_IRK_2001=[{"id": "objective>IRK>2001>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The man who analyzed the first encounter of the Prophet (S.A.W.) with Angel Jibril was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hatib b. Abi Balta'a </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waraqah b. Nawfal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arqam b. Arqam</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Uthman b. <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Affan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Waraqah b. Nawfal was the man who analyzed the first encounter of the Prophet (S.A.W.) with Angel Jibril. He was a cousin of Khadijah (the Prophet's first wife) and a Christian monk who had knowledge of the previous scriptures. When the Prophet (S.A.W.) had his first encounter with Angel Jibril and received the first revelation, he was confused and scared. Khadijah took him to Waraqah who confirmed that the visitor was indeed the Angel Jibril and that Muhammad (S.A.W.) was the last Prophet.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS CALL TO PROPHETHOOD"}, {"id": "objective>IRK>2001>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The main message of the verse above is that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Muslim 'Ummah should ensure that the Glorious Qur'an is not corrupted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protection of the Glorious Qur'an is a divine responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protection of the Glorious Qur'an is a joint responsibility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prophet (S.A.W.) has taken adequate measures to protect the Glorious Qur'an</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main message of the verse above is that the protection of the Glorious Qur'an is a divine responsibility.</div>", "topic": "PROOF OF THE DIVINE AUTHENTICITY OF THE GLORIOUS QUR'AN : DIVINE PRESERVATION OF THE GLORIOUS QUR'AN"}, {"id": "objective>IRK>2001>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above, is an expression of man's absolute </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loyalty to 'Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dependence on 'Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obedience to 'Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humility to 'Allah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse is an expression of man's absolute loyalty to 'Allah.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2001>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In surah al-Qari<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>ah, mankind is compared to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scattered moths </div>", "<div style=\"font-family:Cambria;font-size:17px;\">laden camels </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pampered creatures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">humiliated beasts </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Surah Al-Qari'ah (The Calamity), mankind is compared to scattered moths. This is a metaphor used in the Quran to describe the chaos and terror that will be prevalent on the Day of Judgment. The comparison of people to scattered moths illustrates the helplessness and disarray of mankind on that day.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -QARI'AH"}, {"id": "objective>IRK>2001>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fount (of abundance) was given to the Prophet (S.A.W.) and made known to him in surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Ma<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-Takathur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an-Nasr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Kawthar</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 'Fount of Abundance' was given to the Prophet (S.A.W.) and made known to him in Surah Al-Kawthar. Al-Kawthar is the shortest Surah in the Quran and it was revealed to the Prophet (S.A.W.) at a time when his enemies were rejoicing at his son's death. The Surah gave the Prophet (S.A.W.) the glad tidings of Al-Kawthar, which is a river in Paradise and also signifies abundance.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -KAWTHAR"}, {"id": "objective>IRK>2001>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above is immediately followed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse that follows it is: <br/> إِنَّ هَٰذَا لَفِي ٱلصُّحُفِ ٱلْأُولَىٰ <br/> Translation: \"Indeed, this is in the former scriptures.\" <br/> — Surah Al-A'la (87:18)</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -FALAQ"}, {"id": "objective>IRK>2001>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic theme of surah al-Zil Zal is the description of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fearful events of the Day of Judgement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">how people will be rewarded with Paradise </div>", "<div style=\"font-family:Cambria;font-size:17px;\">events before the actual doomsday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">punishment of the unbelievers in hell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic theme of Surah Al-Zilzal (The Earthquake) is the description of the fearful events of the Day of Judgment. The Surah vividly describes the chaos and terror of the Day of Judgment when the earth will shake its final earthquake, and it will throw out its burdens (the dead), and man will say: 'What is the matter with it?' On that day, it will report its news because your Lord will have inspired it.</div>", "topic": "TAFSIR : IMPORTANCE AND TYPES OF TAFSIR"}, {"id": "objective>IRK>2001>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major theme of ayah Amanar- Rasul is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steadfastness in prayer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the articles of faith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pillars of Islam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the importance of knowledge </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ayah Amanar-Rasul is a verse in the Quran that outlines the articles of faith in Islam. These include belief in Allah, His angels, His books, His messengers, the Day of Judgment, and predestination. Therefore, the major theme of Ayah Amanar-Rasul is the articles of faith.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2001>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Sahaba were the first to embark on the interpretation of the Glorious Qur'an in order to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be known as teachers of Tafstr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bring out the treasures in the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excel above other scholars </div>", "<div style=\"font-family:Cambria;font-size:17px;\">get used to the language of the Glorious Qur'an</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sahaba, who were the companions of the Prophet Muhammad, were the first to embark on the interpretation of the Quran. Their main aim was to understand and bring out the treasures in the Quran, not to be known as teachers of Tafsir or to excel above other scholars. They wanted to understand the teachings of the Quran and apply them in their lives.</div>", "topic": "TAFSIR : HISTORICAL DEVELOPMENT OF TAFSIR"}, {"id": "objective>IRK>2001>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scholar who adopted Tafsir bil Ma'athur in his commentary was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu abdullahi Shaddad B. Aws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">As-Sassas Abu Bakr Ahmed b. Ali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At-Tabari Abu Jafar Muhammad b. Jarir </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al-Qutubi Muhammad Abu Abdullahi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tafsir bil Ma'thur refers to the interpretation of the Quran based on transmitted reports, including sayings of the Prophet Muhammad and his companions. At-Tabari Abu Jafar Muhammad b. Jarir was a renowned scholar who adopted this method in his commentary of the Quran.</div>", "topic": "TAFSIR : HISTORICAL DEVELOPMENT OF TAFSIR"}, {"id": "objective>IRK>2001>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'Asma ar-Rijal' refers to the investigation of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chain of Hadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">content of Hadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">criticism of the narrators </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chronology of the narrators </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">'Asma ar-Rijal' is a discipline in Hadith studies where the credibility of the narrators of Hadith is investigated. This is done to ensure the authenticity of the Hadith. Therefore, 'Asma ar-Rijal' refers to the criticism of the narrators.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2001>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of knowledge of isnad and matn lies in the fact that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both were taught by the Prophet (S.A.W.)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the two make it easy to memorize Hadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the two make it easy to identify fault in Hadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they make it possible to understand Hadith</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Isnad refers to the chain of narrators of a Hadith, while Matn is the content of the Hadith. Knowledge of both is important in Hadith studies as it makes it easy to identify any faults in the Hadith. This is crucial in ensuring the authenticity of the Hadith.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2001>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term al-Mutawatir refers to Hadith narrated by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bukhari and Muslim</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the six sound collectors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Prophet's closest companions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">large number of narrators </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term al-Mutawatir refers to Hadiths that have been narrated by a large number of narrators at each level of their chain of transmission, providing a very high level of authenticity and certainty. Therefore, the correct answer is 'large number of narrators'.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2001>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (S.A.W.) enjoins that if anyone sees an abomination, the least thing to do is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">change it with his hands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">condemn it in public </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hate it in his heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">turn his eyes away</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the Hadith, if anyone sees an abomination, the least thing to do is to hate it in his heart. This is the lowest level of faith. The other levels include speaking out against it or changing it with his hands, but these are not options in the question.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : ENJOINING WHAT IS GOOD AND FORBIDDING WHAT IS WRONG HADITH 25 AND 34 OF AN NAWAWI"}, {"id": "objective>IRK>2001>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Hadith 31 of an-Nawawi, man will be loved by 'Allah if he is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indifferent to the world </div>", "<div style=\"font-family:Cambria;font-size:17px;\">steadfast in prayers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obedient to the prophets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kind to his neighbours </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Hadith 31 of an-Nawawi, one of the ways to be loved by Allah is to be indifferent to the world. This means to not be overly attached to worldly possessions and pleasures, and to focus on spiritual growth and the hereafter.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2001>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The statement in Hadith 25 above gave rise to the explanation as to the different ways by which </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prayers can be offered </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alms can be given </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fasting can be observed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pilgrimage can be performed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement in Hadith 25 gave rise to the explanation as to the different ways by which alms can be given.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2001>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In surah 17:23 'Allah decrees that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">none should be worshipped but Him</div>", "<div style=\"font-family:Cambria;font-size:17px;\">believers should not say what they will not do </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prayers should be observed at their appointed times </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no distinction should be made between the prophets </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Surah 17:23, Allah decrees that none should be worshipped but Him. This is the fundamental principle of Tawhid, the oneness of God, which is the cornerstone of Islamic belief.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2001>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Labour crises could be resolved if employers of labour adhere to the Prophet's advice which says </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pay the labourer before his sweat is dry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is better to cut firewood and sell than to beg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muslims should abstain from idleness </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the honour of a Muslim should not be violated </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet's advice that could help resolve labour crises is to 'pay the labourer before his sweat is dry'. This means that workers should be paid promptly and fairly for their work, which would help to prevent disputes and dissatisfaction.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : DIGNITY OF LABOUR (Q.62:10) (Q.78:11) HADITH FROM BUKHARI AND IBNMAJAH: “THAT ONE OF YOU TAKES HIS ROPE…….” “NEVER HAS ANYONE OF YOU EATEN…..”."}, {"id": "objective>IRK>2001>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q. 2:219 prohibits wine and gambling for the muslims because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they lead to extravagance and intoxication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sins in them are greater than the profits </div>", "<div style=\"font-family:Cambria;font-size:17px;\">one becomes impoverished overnight </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they lead one to ignore one's religion</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah 2:219 of the Quran prohibits Muslims from consuming wine and engaging in gambling because the sins or harm resulting from them are greater than any potential benefits or profits. This is based on the principle of weighing the benefits and harms in Islamic jurisprudence.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : PROHIBITION OF BRIBERY AND CORRUPTION (Q:2:188), ALCOHOL AND GAMBLING (Q.2:219) (Q.5:93-94), STEALING AND FRAUD (Q.5:41) (83:1-5),SMOKING, DRUG ABUSE AND OTHER INTOXICANTS (Q.2:172-173, 195 AND 219) (Q.4:43) (Q.5:3) (Q.6:118-121) ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>2001>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The forbidden type of food listed in surah 2:173 include carrion, blood, swine flesh and that which is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dedicated to other gods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">killed through beating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">killed by goring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">devoured by wild beasts </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah 2:173 of the Quran lists the types of food that are forbidden for Muslims to consume. These include carrion (dead animals), blood, swine flesh (pork), and anything that is dedicated to other than Allah (God). This is because Islam emphasizes the concept of 'Tayyib', which means 'good and pure', and these foods are considered impure or harmful.</div>", "topic": "IBADAT AND THEIR TYPES : TAHARAH, ITS TYPES AND IMPORTANCE AL-ISTINJA'/ISTIJMAR, ALWUDU', AT-TAYAMMUM AND AL-GHUSL HADITH 10 AND 23 OF AN-NAWAWI"}, {"id": "objective>IRK>2001>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The admonition against arrogance in surah 31:18 is directed to the son of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ibrahim</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Musa </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lugman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yusuf</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The admonition against arrogance in Surah 31:18 is directed to the son of Luqman. Luqman was a wise man in Islamic tradition who gave his son various pieces of advice, including the warning against arrogance.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>2001>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'... here are my daughters: they are purer for you ...' (Q. 11: 78) <br/> The statement above was made by Prophet Lut to discourage </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">homosexuality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adultery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fornication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">celibacy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement '... here are my daughters: they are purer for you ...' (Q. 11: 78) was made by Prophet Lut to discourage homosexuality. In the story, the people of Lut were engaging in homosexual behavior, and Lut offered his daughters in marriage to them as a lawful alternative.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : ADULTERY AND FORNICATION (Q.17:32) (Q.24:2), HOMOSEXUALITY (Q.11:77-78) AND OBSCENITY (Q:4:14-15) HADITH – “NO ONE OF YOU SHOULD MEET A WOMAN PRIVATELY …… “BUKHARI"}, {"id": "objective>IRK>2001>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Surah 2:195 above can be interpreted as discouraging </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stealing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bribery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gambling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smoking</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah 2:195 can be interpreted as discouraging smoking.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : PROHIBITION OF BRIBERY AND CORRUPTION (Q:2:188), ALCOHOL AND GAMBLING (Q.2:219) (Q.5:93-94), STEALING AND FRAUD (Q.5:41) (83:1-5),SMOKING, DRUG ABUSE AND OTHER INTOXICANTS (Q.2:172-173, 195 AND 219) (Q.4:43) (Q.5:3) (Q.6:118-121) ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>2001>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mutilation which is stipulated in Q. 5:38 for theft is described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an exemplary punishment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a retaliatory sanction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a punitive measure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an incontrovertible disgrace </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The punishment for theft as stipulated in Q. 5:38 is described as an exemplary punishment. This means it is intended to serve as a deterrent to others. The verse states that a thief, male or female, should have their hand cut off as a recompense for what they committed, as an exemplary punishment from Allah.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : PROHIBITION OF BRIBERY AND CORRUPTION (Q:2:188), ALCOHOL AND GAMBLING (Q.2:219) (Q.5:93-94), STEALING AND FRAUD (Q.5:41) (83:1-5),SMOKING, DRUG ABUSE AND OTHER INTOXICANTS (Q.2:172-173, 195 AND 219) (Q.4:43) (Q.5:3) (Q.6:118-121) ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>2001>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-weight:bold;\"> 'Allah doth command you <br/> To render back your Trusts  <br/> To those to whom they are due; <br/> And when ye judge  <br/> Between mand and man  <br/> That ye judge with justice ...' </span> (Q. 4: 58) <br/> Inherent in the Qur'anic verse above are the virtues of amanah and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diyafah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">karamah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">khushu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>adalah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse quoted in the question is from the Quran (4:58) and it emphasizes the virtues of trustworthiness (amanah) and justice (adalah). The verse instructs to return trusts to their rightful owners and to judge with justice when arbitrating between people. Therefore, the correct answer is 'adalah' which means justice in Arabic.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : TRUST AND OBLIGATIONS (Q:4:58) (Q.5:1) AND PROMISES (Q.16:91) HADITH ‘HE HAS (REALLY) NO FAITH ….. NOT FULFILLED HIS PROMISE” (BAIHAQI)"}, {"id": "objective>IRK>2001>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ar-Rahman as one of the attributes of Allah implies that He is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kind to His servants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more powerful than His servants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an overseer of His servants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">closer to His servants </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ar-Rahman is one of the 99 names of Allah in Islam, and it means 'The Most Merciful'. This attribute of Allah implies His immense kindness and mercy towards His servants. Therefore, the correct answer is 'kind to His servants'.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2001>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The word Hafizin in Q. 82:10 refers to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">man </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jinns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Angels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prophets </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'Hafizin' in Q. 82:10 refers to 'Guardians' or 'Protectors'. In the context of the Quran, these guardians are often interpreted as angels who record the deeds of humans. Therefore, the correct answer is 'Angels'.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH'S ANGELS"}, {"id": "objective>IRK>2001>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prophet who assisted Prophet Ibrahim (A.S.) in the reconstruction of the Ka<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>abah was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ishaq (A.S.)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuh (A.S.)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ya<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>qub (A.S.)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Isma<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>il (A.S.)</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Quran mentions that Prophet Ibrahim (A.S.) and his son Prophet Ismail (A.S.) were the ones who reconstructed the Ka'abah. Therefore, the correct answer is 'Isma'il (A.S.)'.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS BIRTH AND EARLY LIFE"}, {"id": "objective>IRK>2001>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Surah 79:24 reveals that Pharaoh's action incompatible with the Islamic principle of Tawhid because he </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encouraged the art of magic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">indulged in immoral acts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">worshipped beings other than 'Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equaled himself with 'Allah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah 79:24 of the Quran reveals that Pharaoh declared 'I am your supreme lord'. This action is incompatible with the Islamic principle of Tawhid (the oneness of God) because he equated himself with Allah. Therefore, the correct answer is 'equaled himself with 'Allah'.</div>", "topic": "TAWHID AND FIQH : GENERAL PRACTICES WHICH ARE INCOMPATIBLE WITH ISLAMIC PRINCIPLES OF TAWHID"}, {"id": "objective>IRK>2001>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The art of witchcraft is disapproved of in surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ash-shams </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-falaq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Ikhias </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an-Nas </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The art of witchcraft is disapproved of in Surah Al-Falaq. This Surah is a plea to Allah for protection from various evils, including witchcraft.</div>", "topic": "TAWHID AND FIQH : SHIRK"}, {"id": "objective>IRK>2001>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mature Muslim who wakes up only to discover that it was the first day of Ramadan is expected to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">observe imsak and make up </div>", "<div style=\"font-family:Cambria;font-size:17px;\">start his fasting the next day </div>", "<div style=\"font-family:Cambria;font-size:17px;\">compensate the day with kaffarah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">observe imsak without making up</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mature Muslim who wakes up only to discover that it was the first day of Ramadan is expected to observe imsak and make up. Imsak means abstaining from things that invalidate the fast from dawn until sunset. The person is expected to make up for the part of the day they missed fasting.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2001>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zakatul-fitr is not permissible on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maize </div>", "<div style=\"font-family:Cambria;font-size:17px;\">millet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kolanut</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zakatul-fitr is not permissible on kolanut. Zakatul-fitr is a form of charity given to the poor at the end of Ramadan. It can be given in the form of staple food items like rice, maize, and millet, but not kolanut.</div>", "topic": "IBADAT AND THEIR TYPES : ZAKAH"}, {"id": "objective>IRK>2001>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Jihad against carnal self is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">minor jihad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">major jihad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">compulsory jihad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">desirable jihad</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jihad against carnal self is a major jihad. Jihad means struggle or striving. The major jihad is the inner spiritual struggle of the self against evil tendencies and desires.</div>", "topic": "IBADAT AND THEIR TYPES : JIHAD"}, {"id": "objective>IRK>2001>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">' .. . He created for you mates from among yourselves, that ye may dwell in tranquility with them...' (Q. 30: 21) <br/> The verse above discusses the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">need for peace </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reasons for marriage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">need for tranquility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of creation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse 'He created for you mates from among yourselves, that ye may dwell in tranquility with them...' (Q. 30: 21) discusses the reasons for marriage. It highlights the purpose of marriage as a means for spouses to live in tranquility with each other.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2001>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The message contained in the Glorious Qur'an 4:34 centres on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rights and duties of a couple </div>", "<div style=\"font-family:Cambria;font-size:17px;\">position of a husband and wife </div>", "<div style=\"font-family:Cambria;font-size:17px;\">role of a man in the family </div>", "<div style=\"font-family:Cambria;font-size:17px;\">virtues of an ideal husband</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The message contained in the Glorious Qur'an 4:34 centres on the rights and duties of a couple.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2001>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Men and women are considered equal in Q. 16:97 in relation to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">responsibilities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">piety</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intelligence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discipline</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Men and women are considered equal in Q. 16:97 in relation to piety.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2001>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where the husband and wife mutually agree to terminate their marriage contract without anything against each other, such a dissolution is termed </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ila</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faskh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">khul<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">mubara'ah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mubara'ah is a mutual divorce where both husband and wife agree to terminate their marriage contract without any ill feelings towards each other. Ila, Faskh, and Khul<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span> are other forms of divorce in Islamic law, but they do not specifically refer to a mutual agreement without anything against each other.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2001>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The period of custody of a baby girl after her mother has been divorced lasts until she is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">married </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 years old </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 years old</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islamic law, the period of custody of a baby girl after her mother has been divorced lasts until she is married. This is because the responsibility of a woman's protection and maintenance in Islam is on her male relatives, in this case, her husband.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2001>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Islamic law of inheritance, the share of the mother of the deceased who has no children is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/6</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Islamic law of inheritance, the share of the mother of the deceased who has no children is 1/3.</div>", "topic": "FAMILY MATTERS : INHERITANCE"}, {"id": "objective>IRK>2001>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fard and Haram in the scope of shari<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>ah mean </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tolerable and abominable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">permissible and punishable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">compulsory and disliked </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obligatory and prohibited </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of Islamic Shari'ah, 'Fard' refers to an act that is obligatory for Muslims, while 'Haram' refers to anything that is explicitly prohibited by the Quran. Therefore, 'Fard and Haram' mean 'obligatory and prohibited'.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2001>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'If ye do it not, take notice of war from 'Allah and His Apostle: But if ye turn back, ye shall have your capital summs . . .' <br/> (Q. 2: 279) <br/> The quotation above warns against </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fraud </div>", "<div style=\"font-family:Cambria;font-size:17px;\">usury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gambling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quoted verse (Q. 2: 279) is a warning against usury, also known as interest or 'riba' in Arabic. In Islam, usury is strictly prohibited as it is considered exploitative.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : ISLAMIC ATTITUDE TO RIBA HADITH 6TH OF AN-NAWAWI"}, {"id": "objective>IRK>2001>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Who among the prophets of 'Allah was sent to his people to warn against deceit in terms of measurement and weight?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shuaib (A.S.).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hud (A.S.).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Salih (A.S.).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuh (A.S.).</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Shuaib (A.S.) was sent to his people, the Midianites, to warn them against deceit in terms of measurement and weight. He preached against dishonesty in business transactions, which was a common practice among his people.</div>", "topic": "ARTICLE OF FAITH : HIS PROPHETS: ULUL-AZMI"}, {"id": "objective>IRK>2001>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The worst vice prevalent during the Jahiliyyah period was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disloyalty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insincerity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cowardice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vengeance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The worst vice prevalent during the Jahiliyyah period was disloyality.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : JAHILIYYAH PRACTICES: IDOL WORSHIP, INFANTICIDE, POLYANDRY, GAMBLING, USURY, ETC."}, {"id": "objective>IRK>2001>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Jahiliyyah practice that was gradually phased out is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gambling </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adultery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">usury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alcoholism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Jahiliyyah practice that was gradually phased out is alcoholism.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : ISLAMIC REFORMS"}, {"id": "objective>IRK>2001>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the most outstanding developments after the Hijrah was the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emergence of a new religion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in hostilities against the Muslims </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emergence of the Muslim 'Ummah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in cooperation with the Jews </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After the Hijrah, which is the migration of Prophet Muhammad and his followers from Mecca to Medina, one of the most significant developments was the emergence of the Muslim 'Ummah. The term 'Ummah' refers to the collective community of Islamic peoples, which is bound together by ties of religion. In Medina, Prophet Muhammad established a Muslim community and set up a constitution known as the Constitution of Medina which regulated the rights and responsibilities of all citizens and the relationship between the different communities in the city.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE HIJRAH"}, {"id": "objective>IRK>2001>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Makkan forces were not successful at the battle of Khandaq because they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">were afraid of another defeat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ran out of supplies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">were not properly coordinated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">were not familiar with the strategy of the Muslims </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Battle of Khandaq, also known as the Battle of the Trench, was a defensive battle fought by the Muslims led by Prophet Muhammad against the Quraysh of Mecca and their allies. The Makkan forces were not successful because they were not familiar with the strategy of the Muslims. The Muslims had dug a trench around Medina, which was a novel strategy in Arabian warfare and this prevented the Makkan cavalry from breaking through.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>2001>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Who among the four rightly guided caliphs introduced the systems of Bayt al mal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu Bakr as Siddiq</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Umar b. al-Khattab</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Uthman b. <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Affan</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Ali b. ' Abi Talib </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The system of Bayt al-Mal, which is an Arabic term that means 'House of Wealth' and refers to the financial treasury and state treasury in the early Islamic Caliphates, was introduced by Umar b. al-Khattab, the second of the four rightly guided caliphs. He established this system to manage the wealth and the expenditures of the state.</div>", "topic": "THE RIGHTLY GUIDED CALIPHS AL-KHULAFA'U RASHIDUN : THE LIVES AND CONTRIBUTIONS OF THE FOUR RIGHTLY GUIDED CALIPHS"}, {"id": "objective>IRK>2001>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Muslim soldier who introduced Islam into Tripoli was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Uqbah b. N afi<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Uqbah b. Sa<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>ad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sa<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>ad b. Abi Waqas </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span>Amr b. al As</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Uqbah b. Nafi is credited with the introduction of Islam into Tripoli. He was a general in the army of the Umayyad Caliphate and led the Islamic conquest of the Maghreb (North Africa).</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE SPREAD OF ISLAM TO EGYPT"}, {"id": "objective>IRK>2001>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors which helped the spread of Islam in West Africa was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the building of a mosque in Timbuktu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the establishment of many schools </div>", "<div style=\"font-family:Cambria;font-size:17px;\">effective trade relationships </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existence of clans and kingdoms </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors which helped the spread of Islam in West Africa was effective trade relationships. Muslim traders from North Africa and the Middle East travelled to West Africa for trade, and they brought with them the Islamic religion. The interaction between these Muslim traders and the local West African people led to the spread of Islam in the region.</div>", "topic": "THE IMPACT OF ISLAM IN WEST AFRICA : THE INFLUENCE OF ISLAM ON THE SOCIO-POLITICAL LIFE OF SOME WEST AFRICAN EMPIRES: GHANA, MALI, SONGHAI AND BORNO"}, {"id": "objective>IRK>2001>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first man on earth, Adam (A. S.). was exalted above other creatures because of his </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">intelligence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obedience </div>", "<div style=\"font-family:Cambria;font-size:17px;\">insight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">knowledge</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first man on earth, Adam (A.S.), was exalted above other creatures because of his knowledge.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}];
